SurahAIData getAIInfo(String surahId, String surahName) {
  // Clean the surahName to match the keys in our map
  String cleanName = surahName.replaceFirst('سورة ', '').trim();
  
  // Try to find a match in the map (checking if the map key is contained in the cleanName)
  for (var key in surahAIDataMap.keys) {
    if (cleanName.contains(key)) {
      return surahAIDataMap[key]!;
    }
  }

  // Fallback for ID-based matching if name matching fails
  if (surahId.contains('al-baqara')) return surahAIDataMap['البقرة']!;
  if (surahId.contains('al-kahf')) return surahAIDataMap['الكهف']!;
  if (surahId.contains('ya-sin')) return surahAIDataMap['يس']!;
  if (surahId.contains('ar-rahman')) return surahAIDataMap['الرحمن']!;
  if (surahId.contains('al-waqia')) return surahAIDataMap['الواقعة']!;
  if (surahId.contains('al-mulk')) return surahAIDataMap['الملك']!;
  if (surahId.contains('al-ikhlas')) return surahAIDataMap['الإخلاص']!;
  if (surahId.contains('al-falaq')) return surahAIDataMap['الفلق']!;
  if (surahId.contains('an-nas')) return surahAIDataMap['الناس']!;

  // Generic fallback for any missed cases
  return const SurahAIData(
    verseCount: 0,
    summary: 'سورة قرآنية عظيمة تحمل بين طياتها هداية للقلوب وشفاءً للصدور. تتضمن آيات بينات تدعو للتأمل في خلق الله، وتوجه المؤمنين لسبيل الرشاد والتقوى. تلاوتها نور وبركة في الدنيا والآخرة.',
  );
}

